mapper.select:
select khc.*,kol_types from kol_history_celebrity khc inner join ( SELECT celebrity_id, group_concat(DISTINCT kol_type ) as kol_types FROM kol_history_celebrity_detail
and kol_type in
#{item}
and product_name like concat('%', #{kolHistoryCelebrity.productName}, '%')
and brand_name like concat('%', #{kolHistoryCelebrity.brandName}, '%')
GROUP BY celebrity_id ) khcd on khc.id = khcd.celebrity_id
and khc.celebrity_name like concat('%', #{kolHistoryCelebrity.celebrityName}, '%')
and khc.platform_type = #{kolHistoryCelebrity.platformType}
and khc.gender = #{kolHistoryCelebrity.gender}
and khc.country_name = #{kolHistoryCelebrity.countryName}
order by last_submit_date desc
